{
  path_group_menu_->clear();
  clock_menu_->clear();

  filter_index_to_path_group_name_.clear();
  clock_index_to_clock_.clear();

  path_group_name_.clear();
  clock_filter_ = nullptr;
  all_clocks_.clear();
}

