void HistogramView::clear()
{
  buckets_.positive.clear();
  buckets_.negative.clear();

  histogram_ = nullptr;

  chart_->setTitle("");
  chart_->removeAllSeries();

  axis_x_->setTitleText("");
  axis_x_->hide();

  axis_y_->setTitleText("");
  axis_y_->hide();
