{
  return std_cell_area_;
}

int64_t Metrics::getMacroArea() const
{
  return macro_area_;
}

int64_t Metrics::getArea() const
{
  return std_cell_area_ + macro_area_;
}

bool Metrics::empty() const
{
  return num_macro_ == 0 && num_std_cell_ == 0;
}

