    return "Unconstrained IOs";
  }

  if (is_cluster_of_unplaced_io_pins_) {
    return "Unplaced IOs";
  }

  if (is_io_pad_cluster_) {
    return "IO Pad";
  }

  if (is_fixed_macro_) {
    return "Fixed Macro";
  }

  switch (type_) {
    case StdCellCluster:
      cluster_type = "StdCell";
      break;
