float SoftMacro::getMacroUtil() const
{
  if (cluster_ == nullptr || area_ == 0) {
    return 0.0;
  }

  if (cluster_->getClusterType() == HardMacroCluster) {
    return 1.0;
  }

  if (cluster_->getClusterType() == MixedCluster) {
    return cluster_->getMacroArea() / static_cast<float>(area_);
  }

  return 0.0;
}

