                         const char* name,
                         char hier_delimiter = '/');

  ///
  /// Translate a database-id back to a pointer.
  ///
  static dbBlock* getBlock(dbChip* chip, uint32_t oid);

  ///
  /// Translate a database-id back to a pointer.
  ///
