  }
};

class sortITerm
{
  _dbBlock* block_;

 public:
  sortITerm(_dbBlock* block) { block_ = block; }

  bool operator()(uint32_t it1, uint32_t it2)
  {
    _dbITerm* iterm1 = block_->iterm_tbl_->getPtr(it1);
    _dbITerm* iterm2 = block_->iterm_tbl_->getPtr(it2);
